/* eslint-disable jsx-a11y/iframe-has-title */
import React,{useState,useEffect} from 'react'
import CommonSection from '../shared/CommonSection';
import '../styles/tour.css';
import SearchBar from './../shared/Search';
import TourCard from './../shared/TourCard.jsx' ;
import NewsLetter from './../shared/Newsletter';
import { Col, Container,Row,  } from 'reactstrap';
import { BASE_URL } from '../utils/config.js';
import useFetch from '../hooks/useFetch.js';
const Tours = () => {
  const [pageCount, setPageCount] = useState(0);
  const [page,setPage] = useState(0);
  const {data:tours}= useFetch(
    `${BASE_URL}/tours/:id`
  );
  console.log(tours);
  featuredTours?.map(tour=>(
    <Col lg='3' className='mb-4' key={tour._id}><TourCard tour={tour}/></Col>
   ))

  useEffect(()=>{

    const pages=Math.ceil(5/4) //later we will use backend data count 
    setPageCount(pages)
  },[page])
  return (
    <div>
      <CommonSection title={"All Tours"}/>
      <section>
            <Container>
              <Row>
         <SearchBar/>
              </Row>
            </Container>
      </section>
      <section className='pt-0'>
        <Container>
          <Row>
            {
              
              tours.map(tour=>(
                <Col lg='3' className='mb-4' key={tours._id}><TourCard tour={tours}/></Col>
               ))


            
               }
              <Col lg='12'>
              <div className="pagination d-flex align-items-center justify-content-center
              mt-4 gap-3">
                {[...Array(pageCount).keys()].map(number=>(
                  <span key={number} onClick={()=>setPage(number)}
                  className={page===number ? 'active_page' : ""}
                  >
                    {number+1}
                  </span>
                ))}

              </div>
              </Col>
          </Row>
        </Container>
      </section>
      <NewsLetter/>
    </div>
  )
}

export default Tours
